### [최적화 2] Redis 캐시 전략

**캐시 적용 대상 및 TTL 설계**

| 캐시 키 패턴 | 데이터 | TTL | 무효화 시점 |
|---|---|---|---|
| `call:queue:waiting` | 대기 중인 유저 ID Set | 5초 | 입장/퇴장/매칭 완료 |
| `user:profile:{userId}` | 프로필(나이,지역,관심사) | 10분 | 프로필 수정 |
| `user:block:{userId}` | 차단 목록 | 5분 | 차단/해제 |
| `call:matching:lock:{userId}` | 매칭 중 락 | 30초 | 매칭 완료/실패 |

```kotlin
// CallMatchingCacheService.kt
@Service
class CallMatchingCacheService(
    private val redisTemplate: RedisTemplate<String, String>,
    private val objectMapper: ObjectMapper
) {
    companion object {
        const val WAITING_QUEUE_KEY = "call:queue:waiting"
        const val USER_PROFILE_PREFIX = "user:profile:"
        const val BLOCK_LIST_PREFIX = "user:block:"
        const val MATCHING_LOCK_PREFIX = "call:matching:lock:"
    }

    // 대기 큐: Redis Sorted Set (score = 입장 timestamp, 선입선출 보장)
    fun addToWaitingQueue(userId: String) {
        val score = System.currentTimeMillis().toDouble()
        redisTemplate.opsForZSet().add(WAITING_QUEUE_KEY, userId, score)
        redisTemplate.expire(WAITING_QUEUE_KEY, Duration.ofMinutes(10))
    }

    fun removeFromWaitingQueue(userId: String) {
        redisTemplate.opsForZSet().remove(WAITING_QUEUE_KEY, userId)
    }

    // 오래 기다린 순서대로 후보 추출 (공정성 보장)
    fun getWaitingCandidates(limit: Long = 50): Set<String> {
        return redisTemplate.opsForZSet()
            .range(WAITING_QUEUE_KEY, 0, limit - 1)
            ?: emptySet()
    }

    // 프로필 캐시
    fun getUserProfile(userId: String): UserProfileCache? {
        val json = redisTemplate.opsForValue().get("$USER_PROFILE_PREFIX$userId")
        return json?.let { objectMapper.readValue(it, UserProfileCache::class.java) }
    }

    fun setUserProfile(userId: String, profile: UserProfileCache) {
        redisTemplate.opsForValue().set(
            "$USER_PROFILE_PREFIX$userId",
            objectMapper.writeValueAsString(profile),
            Duration.ofMinutes(10)
        )
    }

    // 분산 락: 동시 매칭 요청 방지
    fun acquireMatchingLock(userId: String): Boolean {
        return redisTemplate.opsForValue().setIfAbsent(
            "$MATCHING_LOCK_PREFIX$userId",
            "locked",
            Duration.ofSeconds(30)
        ) ?: false
    }

    fun releaseMatchingLock(userId: String) {
        redisTemplate.delete("$MATCHING_LOCK_PREFIX$userId")
    }

    // 차단 목록 캐시
    fun getBlockList(userId: String): Set<String> {
        return redisTemplate.opsForSet().members("$BLOCK_LIST_PREFIX$userId")
            ?: emptySet()
    }
}
```

```kotlin
// CallMatchingService.kt - 캐시 통합
@Service
@Transactional
class CallMatchingService(
    private val cacheService: CallMatchingCacheService,
    private val matchingQueryRepository: CallMatchingQueryRepository,
    private val callRoomRepository: CallRoomRepository
) {

    fun requestMatching(userId: String): MatchingResult {
        // 1. 분산 락으로 중복 매칭 요청 차단
        if (!cacheService.acquireMatchingLock(userId)) {
            throw AlreadyMatchingException("이미 매칭 중입니다.")
        }

        return try {
            // 2. Redis 대기 큐에서 후보 조회 (DB 미접근)
            val candidates = cacheService.getWaitingCandidates()
                .filter { it != userId }
                .filter { !cacheService.getBlockList(userId).contains(it) }

            if (candidates.isEmpty()) {
                // 대기 큐에 등록
                cacheService.addToWaitingQueue(userId)
                MatchingResult.Waiting
            } else {
                // 3. 캐시된 프로필로 매칭 조건 필터링 (DB 미접근)
                val matched = candidates.firstOrNull { candidateId ->
                    val profile = cacheService.getUserProfile(candidateId)
                        ?: loadAndCacheProfile(candidateId) // 캐시 미스 시만 DB 조회
                    isMatchConditionMet(userId, profile)
                }

                if (matched != null) {
                    cacheService.removeFromWaitingQueue(matched)
                    createCallRoom(userId, matched)
                    MatchingResult.Matched(matched)
                } else {
                    cacheService.addToWaitingQueue(userId)
                    MatchingResult.Waiting
                }
            }
        } finally {
            cacheService.releaseMatchingLock(userId)
        }
    }

    private fun loadAndCacheProfile(userId: String): UserProfileCache {
        // 캐시 미스 시만 DB 조회 (Cache-Aside 패턴)
        val profile = matchingQueryRepository.findProfileForMatching(userId)
        cacheService.setUserProfile(userId, profile)
        return profile
    }
}
```

예상 개선: DB 쿼리 0회(캐시 히트 시), 응답 시간 ~2,000ms -> ~15ms (99% 감소, 캐시 히트 기준).

